import { Link, NavLink, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { clearAuth, getAuth } from "../utils/auth";

export default function Navbar() {
  const navigate = useNavigate();
  const [auth, setAuthState] = useState(getAuth());

  useEffect(() => {
    const refresh = () => setAuthState(getAuth());
    window.addEventListener("auth-change", refresh);
    window.addEventListener("storage", refresh);

    return () => {
      window.removeEventListener("auth-change", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  const isLogged = !!auth?.token;
  const role = auth?.role; // admin | manager | staff | user

  const isCustomer = isLogged && role === "user";
  const isStaff = isLogged && (role === "staff" || role === "manager" || role === "admin");
  const isManager = isLogged && (role === "manager" || role === "admin");
  const isAdmin = isLogged && role === "admin";

  const linkClass = ({ isActive }) =>
    `navLink ${isActive ? "navLinkActive" : ""}`;

  return (
    <nav className="nav">
      <div className="navInner">
        {/* Brand */}
        <Link to="/" className="brand" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <img src="/logo.svg" alt="Leaf Lanka" style={{ width: '40px', height: '40px', objectFit: 'contain' }} />
          <span style={{ fontWeight: 700, color: 'var(--text)', fontSize: '16px' }}>Leaf Lanka</span>
        </Link>

        {/* Links */}
        <div className="navLinks">
          <NavLink to="/" className={linkClass}>Home</NavLink>
          <NavLink to="/vehicles" className={linkClass}>Vehicles</NavLink>

          {/* Customer */}
          {isCustomer && (
            <>
              <NavLink to="/book-appointment" className={linkClass}>Book</NavLink>
              <NavLink to="/my-appointments" className={linkClass}>My Appointments</NavLink>
            </>
          )}

          {/* Staff */}
          {isStaff && (
            <>
              <NavLink to="/appointments" className={linkClass}>Appointments</NavLink>
              <NavLink to="/documents" className={linkClass}>Documents</NavLink>
            </>
          )}

          {/* Manager/Admin */}
          {isManager && (
            <>
              <NavLink to="/vehicles/add" className={linkClass}>Add Vehicle</NavLink>
              <NavLink to="/sales" className={linkClass}>Sales</NavLink>
            </>
          )}

          {/* Admin only */}
          {isAdmin && (
            <>
              <NavLink to="/admin/dashboard" className={linkClass}>Dashboard</NavLink>
              <NavLink to="/admin/create-staff" className={linkClass}>Create Staff</NavLink>
              <NavLink to="/admin/staff" className={linkClass}>Staff List</NavLink>
            </>
          )}
        </div>

        {/* Right side */}
        <div className="navRight">
          {!isLogged ? (
            <>
              <Link to="/login" className="btn btnPrimary btnSm">Login</Link>
              <Link to="/register" className="btn btnSm">Register</Link>
            </>
          ) : (
            <>
              <span className="chip" title="Your role">
                <span className="chipDot" />
                {role}
              </span>

              <button onClick={logout} className="btn btnDanger btnSm">
                Logout
              </button>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
